python3 -c "
import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
for name in wb.sheetnames:
    ws = wb[name]
    print(f'Sheet: {name}, dims: {ws.dimensions}')
    for row in ws.iter_rows(min_row=1, max_row=min(ws.max_row,10), values_only=False):
        for cell in row:
            print(f'  {cell.coordinate}: value={cell.value!r}, number_format={cell.number_format!r}')
"
